import numpy as np

# {This algorithm identifies the next node by maximizing the average distance to already visited nodes to encourage exploration while minimizing travel distance to focus on efficiency.}

def select_next_node(current_node, truck_nodes, depot_node, unvisited_nodes, distance_matrix):
    available_nodes = set(unvisited_nodes) - set(truck_nodes)
    if not available_nodes:
        return None

    best_score = float('-inf')
    next_node = None

    for node in available_nodes:
        distance_to_current = distance_matrix[current_node][node]

        visited_nodes = [n for n in range(len(distance_matrix)) if n not in unvisited_nodes]
        if visited_nodes:
            average_distance_to_visited = np.mean([distance_matrix[node][v_node] for v_node in visited_nodes])
        else:
            average_distance_to_visited = 0

        score = average_distance_to_visited - distance_to_current

        if score > best_score:
            best_score = score
            next_node = node

    return next_node

import numpy as np

def select_next_node(current_node, truck_nodes, depot_node, unvisited_nodes, distance_matrix):
    available_nodes = set(unvisited_nodes) - set(truck_nodes)
    if not available_nodes:
        return None

    # {The new algorithm selects the next node by maximizing the inverse weighted sum of the normalized distance from the current node and the range of distances to all unvisited nodes to encourage diversity in route progression.}
    best_score = float('-inf')
    next_node = None

    for node in available_nodes:
        distance_to_current = distance_matrix[current_node][node]
        if distance_to_current != 0:
            normalized_distance = 1 / distance_to_current
        else:
            normalized_distance = float('inf')

        distances_to_unvisited = [distance_matrix[node][other_node] for other_node in available_nodes if other_node != node]
        if distances_to_unvisited:
            range_of_distances = max(distances_to_unvisited) - min(distances_to_unvisited)
        else:
            range_of_distances = 0

        score = normalized_distance + range_of_distances

        if score > best_score:
            best_score = score
            next_node = node

    return next_node
